def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_total_travel_time = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        total_travel_time = 0

        for truck_pos in all_truck_pos:
            travel_time = np.linalg.norm(truck_pos - customer_pos) / truck_speed
            total_travel_time = max(total_travel_time, travel_time)

        travel_time_cur = np.linalg.norm(cur_truck_pos - customer_pos) / truck_speed
        arrival_time = current_time + travel_time_cur
        time_window = time_windows[i]

        if arrival_time < time_window[0]:
            wait_time = time_window[0] - arrival_time
        elif arrival_time > time_window[1]:
            wait_time = float('inf')
        else:
            wait_time = 0

        total_travel_time += travel_time_cur + wait_time

        if total_travel_time < min_total_travel_time:
            min_total_travel_time = total_travel_time
            best_node = i

    return best_node
